firmware_template.source:
#include "buzzer.h"
#include <Arduino.h>
#define BUZZER_PIN 15
#define BUZZER_CHANNEL 0
void buzzer_setup() {
  ledcAttach(BUZZER_PIN, 2000, 8);
  Serial.println("[buzzer] OK pin=15");
}
void buzzer_tone(uint16_t freq, uint16_t dur) {
  ledcWriteTone(BUZZER_PIN, freq);
  delay(dur);
  ledcWriteTone(BUZZER_PIN, 0);
}
void buzzer_beep() { buzzer_tone(1000, 100); }
void buzzer_alarm() {
  for (int i = 0; i < 3; i++) {
    buzzer_tone(2000, 200);
    delay(100);
  }
}
void buzzer_off() { ledcWriteTone(BUZZER_PIN, 0); }
